  ('pukao-d0d1b9a2-moex-00084', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '有關財務報表的資訊皆具備攸關性與忠實表述兩項基本品質特性時，則可藉由強化品質特性提供 協助選擇，下列何者非為強化性品質特性？', '["可比性", "可驗證性", "中立性", "可了解性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00085', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司被同業控告侵犯專利權，並要求賠償，甲公司的法律顧問評估甲公司很有可能敗訴，可能 的賠償金額在$1,000,000至$5,000,000之間，其機率分布如下： 金 額 機率 $1,500,000 10% $3,500,000 85% $5,000,000 5% 則甲公司有關該訴訟之會計處理為何？', '["應認列負債準備$3,375,000", "應認列負債準備$1,000,000 並附註揭露或有負債$3,500,000", "應認列負債準備$3,500,000", "僅附註揭露或有負債金額為$1,000,000至$5,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00086', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '下列有關國際財務報導準則之敘述何者錯誤？', '["國際財務報導準則各號IFRS準則之內容包含生效日規定", "國際財務報導準則各號IFRS準則之內容包含過渡規定", "國際財務報導準則各號IFRS準則之內容包含應用指引", "國際財務報導準則各號IFRS準則之內容包含釋例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00087', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '乙公司於 X9 年 6 月 17 日溢價發行轉換價格＄50 的可轉債，發行價格為$99,000，債券面額為 $85,000，是日相同條件但不可轉換的公司債其公允價值為$87,000。10 月初乙公司的股價上漲到 $70，該公司普通股面額為$10，可轉債持有人全部將可轉債轉換為乙公司的股票，下列轉換日相 關分錄何者正確？', '["貸方：普通股股本$17,600", "借方：應付公司債$99,000", "借方：資本公積-認股權$11,000", "貸方：資本公積-普通股發行溢價 $82,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00088', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司權益在X4年1月1日有普通股股本$1,000,00（0 每股面額$10），資本公積-發行溢價$200,000 及保留盈餘$600,000。當年4月1日以每股$20買回庫藏股8,000 股，於同年8月1日以每股$23 出售庫藏股 3,500 股，同年10月1日以每股$17出售庫藏股4,000 股，同年12月1日將其餘庫 藏股註銷，請問註銷後甲公司的保留盈餘總額為何？', '["$600,000", "$598,500", "$577,500", "$594,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00089', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', 'A公司X4年度銷貨收入$10,000，銷貨成本$8,800；期初應收帳款$600、期初存貨$640、期初應 付帳款$3,800；期末各科目餘額分別為應收帳款$880、存貨$720、應付帳款$3,920；則本期支付供 應商貨款金額是多少？', '["$9,000", "$8,760", "$8,560", "$8,880"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00090', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X4年1月1日流通在外普通股 72,000股，X4年間普通股之交易如下： 2月1日進行 每股分割為3股之股票分割； 4月1日發放20%股票股利；6月1日發行普通股 12,000股； 10 月1日買回庫藏股票 19,200股。該年度甲公司淨利$1,000,000，累積特別股100,000股，每股股 利1元，請問X4年度甲公司的基本每股盈餘約為多少？ （每股盈餘計算至小數點第二位）', '["$3.25", "$2.44", "$3.44", "$4.43"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00091', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', 'X4年 4 月 1 日，A 公司發行了面額$1,000,000，票面利率為10% 的5年期債券，半年付息一 次，市場有效利率為 12%。 試問發行債券價格約為多少？（四捨五入取至整數） 年金現值 複利現值 5%，10期 7.72174 0.61391 6%，10期 7.36009 0.55840 10%，5期 3.79079 0.62092 12%，5期 3.60478 0.56743', '["$558,400", "$567,430", "$747,669", "$926,405"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00092', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '依據國際會計準則ISA38「無形資產」之規定，發展階段之支出若同時符合下列條件，應認列為 無形資產，請問下列條件何者錯誤？', '["完成該無形資產已達技術可行性，使該無形資產將可供使用或出售", "意圖完成該無形資產，並加以使用或出售", "有能力使用或出售無形資產", "研究階段歸屬於無形資產之支出能可靠衡量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00093', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', 'A公司在X0年12月3 日以每股$20購買B公司25%普通股9,000股。B公司X1年及X2年資 料如下： 公司淨利 每股發放現金股利 年底每股市價 X1年 $100,000 $1 $25 X2年 $100,000 $2 $40 請問 A 公司若將投資 B 公司股票列入採權益法之投資或列入透過損益按公允價值衡量之金融資 產，則對A公司X2年度損益之影響，何者正確？', '["採權益法之投資淨利增加$45,000", "採權益法之投資淨利增加$35,000", "透過損益按公允價值衡量之金融資產淨利增加$153,000", "透過損益按公允價值衡量之金融資產淨利增加$135,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
